int interlace_line(int height, int line)
/* return the actual line # used to store an interlaced line */
{
    int res;

    /*@-shiftimplementation@*/
    if ((line & 7) == 0) {
	return line >> 3;
    }
    res = (height+7) >> 3;
    if ((line & 7) == 4) {
	return res+((line-4) >> 3);
    }
    res += (height+3) >> 3;
    if ((line & 3) == 2) {
	return res + ((line-2) >> 2);
    }
    return res + ((height+1) >> 2) + ((line-1) >> 1);
    /*@=shiftimplementation@*/
}

int inv_interlace_line(int height, int line)
/* inverse function of above, used for recovery of interlaced images */
{
    /*@-shiftimplementation@*/
    if ((line << 3)<height) {
	return line << 3;
    }
    line -= (height+7) >> 3;
    if ((line << 3) + 4 < height) {
	return (line << 3) + 4;
    }
    line -= (height+3) >> 3;
    if ((line << 2) + 2 < height) {
	return (line << 2) + 2;
    }
    line -= (height + 1) >> 2;
    return (line << 1) + 1;
    /*@=shiftimplementation@*/
}

static bool is_gray(png_color c)
{
    /* check if r==g==b, moved to function to work around NeXTstep 3.3 cc bug.
     * life could be so easy if at least the basic tools worked as expected.
     */
    return c.red == c.green && c.green == c.blue;
}

static int writefile(struct GIFelement *s, struct GIFelement *e, 
		     FILE *fp, bool lastimg)
{
    int i;
    struct GIFimagestruct *img = e->imagestruct;
    unsigned long *count = img->color_count;
    GifColor *colors = img->colors;
    int colors_used = 0;
    byte remap[MAXCMSIZE];
    png_struct *png_ptr;
    png_info *info_ptr;
    int p;
    png_color pal_rgb[MAXCMSIZE];
    png_byte pal_trans[MAXCMSIZE];
    png_color_16 color16trans, color16back;
    byte buffer[24]; /* used for gIFt and gIFg */
    int j;
    png_uint_16 histogr[MAXCMSIZE];
    int passcount;
    int errtype, errorcount = 0;
    png_text software;
    png_text comment;

    /* these volatile declarations prevent gcc warnings ("variable might be
     *  clobbered by `longjmp' or `vfork'") */
    volatile bool gray = true;
    volatile int last_color = 0;
    volatile bool remapping = false;
    volatile int bitdepth;

    /*@-nullpass@*/
    png_ptr = png_create_read_struct(PNG_LIBPNG_VER_STRING, NULL, NULL, NULL);
    if (png_ptr == NULL) {
	(void)fprintf(stderr, "gif2png: fatal error, out of memory\n");
	(void)fprintf(stderr, "gif2png: exiting ungracefully\n");
	exit(1);
    }
    info_ptr = png_create_info_struct(png_ptr);
    if (info_ptr == NULL) {
	(void)fprintf(stderr, "gif2png: fatal error, out of memory\n");
	(void)fprintf(stderr, "gif2png: exiting ungracefully\n");
	exit(1);
    }
    /*@=nullpass@*/

    /* pacify splint by defining all this storage */
    memset(remap, '\0', sizeof(remap));
    memset(pal_rgb, '\0', sizeof(pal_rgb));
    memset(pal_trans, '\0', sizeof(pal_trans));

    /* ignore the transparency value if no pixel in the image uses it */
    if (img->trans != -1 && count[img->trans] == 0)
	img->trans = -1;

    if (optimize) {
	/* zero out unused color table entries and use zlib level 9 */
	for (i = 0; i < MAXCMSIZE; i++)
	    if(count[i] == 0)
		colors[i].red = colors[i].green = colors[i].blue = 0;
	/*
	 * The way that last_color is computed ensures that trailing zeroed-out
	 * entries will be dropped.
	 * FIXME: someday, actually compact unused colors out of the table
	 * and remap pixels appropriately.
	 */
    } else if (!recover) {
	/* report unused colors so user can choose to reconvert */
	int unused = 0;

	for (i = 0; i < MAXCMSIZE; i++)
	    if (count[i] == 0)
		unused++;

	if (unused > 0)
	{
	    (void)fprintf(stderr, 
			  "gif2png: %d unused colors; convert with -O to remove\n",
			  unused);
	    errorcount++;
	}
    }

    for (i = 0; i < MAXCMSIZE; i++)
	if (count[i] != 0) {
	    gray &= is_gray(colors[i]);
	    colors_used++;
	    if (last_color < i) 
		last_color = i;
	}

    if (gray) {
	if (verbose > 1)
	    (void)fprintf(stderr, "gif2png: input image is grayscale\n");

	if (img->trans != -1) {
	    for (i = 0; i < MAXCMSIZE; i++) {
		if (i!=img->trans && colors[i].red == colors[img->trans].red) {
		    gray = false;
		    if (verbose > 1)
			(void)fprintf(stderr,
				      "gif2png: transparent color is repeated in visible colors, using palette\n");
		    break;
		}
	    }
	}
    }

    bitdepth = 8;
    if (last_color<16) bitdepth = 4;
    if (last_color<4) bitdepth = 2;
    if (last_color<2) bitdepth = 1;

    if (gray) {
	bool low_prec;
	int gray_bitdepth;
	remapping = true;
	for (i = 0; i < MAXCMSIZE; i++)
	    remap[i] = colors[i].red;

	gray_bitdepth = 8;

	/* try to adjust to 4-bit precision grayscale */

	low_prec = true;
	for (i = 0; i < MAXCMSIZE; i++) {
	    if ((remap[i]&0xf)*0x11 != remap[i]) {
		low_prec = false;
		break;
	    }
	}
	if (low_prec) {
	    for (i = 0; i < MAXCMSIZE; i++) {
		remap[i] &= 0xf;
	    }
	    gray_bitdepth = 4;
	}

	/* try to adjust to 2-bit precision grayscale */

	if (low_prec) {
	    for (i = 0; i < MAXCMSIZE; i++) {
		if ((remap[i]&3)*5 != remap[i]) {
		    low_prec = false;
		    break;
		}
	    }
	}

	if (low_prec) {
	    for (i = 0; i < MAXCMSIZE; i++) {
		remap[i] &= 3;
	    }
	    gray_bitdepth = 2;
	}

	/* try to adjust to 1-bit precision grayscale */

	if (low_prec) {
	    for (i = 0; i < MAXCMSIZE; i++) {
		if ((remap[i]&1)*3 != remap[i]) {
		    low_prec = false;
		    break;
		}
	    }
	}
	if (low_prec) {
	    for (i = 0; i < MAXCMSIZE; i++) {
		remap[i] &= 1;
	    }
	    gray_bitdepth=1;
	}

	if (bitdepth<gray_bitdepth) {
	    gray = false;		/* write palette file */
	    remapping = false;
	} else {
	    bitdepth = gray_bitdepth;
	}
    }

    if (verbose > 1)
	(void)fprintf(stderr, "gif2png: %d colors used, highest color %d, %s, bitdepth %d\n",
		      colors_used, last_color, gray ? "gray":"palette", bitdepth);

    if (verbose > 2)
	for (i = 0; i <= last_color; i++) {
	    (void)fprintf(stderr, "(%3d, %3d, %3d)\n", 
			  colors[i].red, colors[i].blue, colors[i].green);  
	}

    if (setjmp(png_jmpbuf(png_ptr)) != 0) {
	(void)fprintf(stderr, "gif2png:  libpng returns fatal error condition\n");
	(void)free(png_ptr);
	(void)free(info_ptr);
	return 1;
    }

    /* Create and initialize the png_struct with the desired error handler
     * functions.  If you want to use the default stderr and longjump method,
     * you can supply NULL for the last three parameters.  We also check that
     * the library version is compatible with the one used at compile time,
     * in case we are using dynamically linked libraries.  REQUIRED.
     */
    /*@-nullpass@*/
    png_ptr = png_create_write_struct(PNG_LIBPNG_VER_STRING,
				      (void *)NULL, NULL, NULL);

    /*@=nullpass@*/
    if (png_ptr == NULL)
	return(2);

    /* Allocate/initialize the image information data.  REQUIRED */
    info_ptr = png_create_info_struct(png_ptr);
    if (info_ptr == NULL)
    {
	/*@i1@*/png_destroy_write_struct(&png_ptr,  (png_infopp)NULL);
	return(2);
    }

    /* if errtype is not 1, this was generated by fatal() */ 
    if ((errtype = setjmp(png_jmpbuf(png_ptr))) != 0) {
	png_destroy_write_struct(&png_ptr, &info_ptr);
	return errtype;
    }

    /* use standard C streams */
    png_init_io(png_ptr, fp);

    if(optimize)
       png_set_compression_level(png_ptr, Z_BEST_COMPRESSION);

    if (gamma_srgb)
    {
          png_set_gAMA(png_ptr, info_ptr, 1./2.2);
#if (PNG_LIBPNG_VER > 96)
	  png_set_sRGB(png_ptr, info_ptr, PNG_sRGB_INTENT_PERCEPTUAL);
#endif
    }

    /* set basic image properties: width/height, type, bit depth, interlace */
    if (interlaced == PNG_INTERLACE_LAST)
	interlaced = current->imagestruct->interlace!=0 ? PNG_INTERLACE_ADAM7 : PNG_INTERLACE_NONE;

    png_set_IHDR(png_ptr, info_ptr, 
		 current->imagestruct->width, current->imagestruct->height,
		 bitdepth, 
		 gray ? PNG_COLOR_TYPE_GRAY : PNG_COLOR_TYPE_PALETTE,
		 interlaced, 
		 PNG_COMPRESSION_TYPE_DEFAULT, PNG_FILTER_TYPE_DEFAULT);

    /* if the GIF specified an aspect ratio, turn it into a pHYs chunk */
    if (GifScreen.AspectRatio != 0 && GifScreen.AspectRatio != 49)
	png_set_pHYs(png_ptr, info_ptr, 
		     GifScreen.AspectRatio+15, 64, PNG_RESOLUTION_UNKNOWN);

    /* if the GIF specified an image offset, turn it into a oFFs chunk */
    if (img->offset_x>0 && img->offset_y>0)
	png_set_oFFs(png_ptr, info_ptr, 
		     img->offset_x, img->offset_y, PNG_OFFSET_PIXEL);

    if (GifScreen.Background > 0) { /* no background for palette entry 0 */
	/* if the background color doesn't appear in local palette, we just
	   leave it out, if the pic is part of an animation, at least some will
	   use the global palette */

	if (gray) {
	    if (is_gray(GifScreen.ColorMap[GifScreen.Background])) {
		color16back.gray = remap[GifScreen.Background];
		/*@-compdef@*/
		png_set_bKGD(png_ptr, info_ptr, &color16back);
		/*@=compdef@*/
	    }
	} else {
	    for (i = 0; i < MAXCMSIZE; i++) {
		if (GifScreen.ColorMap[GifScreen.Background].red == colors[i].red &&
		    GifScreen.ColorMap[GifScreen.Background].green == colors[i].green &&
		    GifScreen.ColorMap[GifScreen.Background].blue == colors[i].blue) {
		    if (last_color < i) 
			last_color = i;
		    color16back.index = (png_byte)i;
		    /*@-compdef@*/
		    png_set_bKGD(png_ptr, info_ptr, &color16back);
		    /*@=compdef@*/
		    break;
		}
	    }
	}
    }

    /* transparency handling */
    if (img->trans != -1) {
	if (gray) {
	    if (verbose > 2)
		(void)fprintf(stderr, 
			      "gif2png: handling grayscale transparency\n");
	    color16trans.gray = remap[img->trans];
	    /*@-nullpass -compdef@*/
	    png_set_tRNS(png_ptr, info_ptr, NULL, 0, &color16trans);
	    /*@=nullpass =compdef@*/
	} else {
	    if (verbose > 2)
		(void)fprintf(stderr, 
			      "gif2png: handling palette transparency\n");
	    /* GRR NOTE: may be inconsistent with background-color logic (above) */
	    remapping = true;
	    for (i = 0; i < MAXCMSIZE; i++)
		remap[i] = (byte)i;
	    remap[0] = (byte)img->trans;
	    remap[img->trans] = 0;
	    pal_trans[0] = 0;
	    /*@-nullpass@*/
	    png_set_tRNS(png_ptr, info_ptr, pal_trans, 1, NULL);
	    /*@=nullpass@*/
	}
    }

    /* generate the PNG palette */
    if (!gray) {
	png_color *pltep;
	if (remapping) {
	    if (verbose > 2)
		(void)fprintf(stderr, "Remapping palette...\n");
	    for (i = 0; i <= last_color; i++) {
		pal_rgb[i].red   = current->imagestruct->colors[remap[i]].red;
		pal_rgb[i].green = current->imagestruct->colors[remap[i]].green;
		pal_rgb[i].blue  = current->imagestruct->colors[remap[i]].blue;
	    }
	    pltep = pal_rgb;
	} else {
	    if (verbose > 2)
		(void)fprintf(stderr, "Palette copied from GIF colors...\n");
	    pltep = current->imagestruct->colors;
	}
	png_set_PLTE(png_ptr, info_ptr, pltep, last_color+1);

	if (verbose > 2) {
	    (void)fprintf(stderr,
			  "PNG palette generated with %d colors:\n",
			  last_color+1);
	    for (i = 0; i <= last_color; i++) {
		(void)fprintf(stderr, "(%3d, %3d, %3d)\n", 
			      pltep[i].red, pltep[i].blue, pltep[i].green);  
	    }
	}
    }

    /* generate histogram chunk for paletted images only */
    if (histogram && !gray) {
	unsigned long hist_maxvalue = 0;
	for (i = 0; i < MAXCMSIZE; i++)
	    if (count[i]>hist_maxvalue)
		hist_maxvalue = count[i];
	if (hist_maxvalue <= 65535) {
	    /* no scaling necessary */
	    for (i = 0; i < MAXCMSIZE; i++)
		histogr[i] = (png_uint_16)count[i];
	} else {
	    for (i = 0; i < MAXCMSIZE; i++)
		if (count[i] != 0) {
		    histogr[i] = (png_uint_16)
#ifdef __GO32__
			/* avoid using fpu instructions on djgpp, so we don't need emu387 */
			(((long long)count[i]*65535)/hist_maxvalue);
#else
		    ((double)count[i]*65535.0/hist_maxvalue);
#endif
		    if (histogr[i] == 0)
			histogr[i] = 1;
		} else {
		    histogr[i] = 0;
		}
	}
	png_set_hIST(png_ptr, info_ptr, histogr);
    }

    /* transcribe software chunk if necessary */
    /*@-observertrans -statictrans@ -unqualifiedtrans -branchstate*/
    if (software_chunk) {
	software.compression = PNG_TEXT_COMPRESSION_NONE;
	software.key = "Software";
	software.text = (char*)version;
	software.text_length = strlen(software.text);

	png_set_text(png_ptr, info_ptr, &software, 1);
    }
    /*@=observertrans =statictrans =unqualifiedtrans =branchstate@*/

    png_write_info(png_ptr, info_ptr);

    if (bitdepth<8)
	png_set_packing(png_ptr);

    /* loop over elements until we reach the image or the last element if
       this is the last image in a GIF */

    while(lastimg ? s != NULL : s != e->next) {
	byte *data;
	switch((byte)s->GIFtype) {
        /*@-branchstate@*/
	case GIFimage:
	    passcount = png_set_interlace_handling(png_ptr);
	    for (p = 0; p<passcount;p++)
		for (i = 0; i < (int)current->imagestruct->height; i++) {
		    if (progress) {
			if (passcount>1)
			    (void)fprintf(stderr, "%d/%d ", p+1, passcount);
			(void)fprintf(stderr, "%2d%%\r",
				      (int)(((long)i*100)/current->imagestruct->height));
			(void)fflush(stderr);
		    }
		    data = current->data + 
				       (long) (img->interlace!=0 ?
					       interlace_line((int)current->imagestruct->height,i) : i) * current->imagestruct->width;
		    /* we have to remap once */
		    if (remapping && p == 0)
		    {
			for (j = 0; j < (int)img->width; j++) {
			    data[j] = remap[data[j]];
			}
		    }
		    png_write_row(png_ptr, data);
		}
	    break;

	case GIFcomment:
	    j = (int)s->size;
	    /* some GIF encoders produce trailing garbage and NULs */
	    if (j > 0 && ((s->data[j-1] == '\0') || (s->data[j-1] & 0x80)!=0))
		--j;
	    /*@-observertrans -statictrans @*/
	    comment.key = "Comment";
	    if (j<500) {
		comment.compression = PNG_TEXT_COMPRESSION_NONE;
	    } else {
		comment.compression = PNG_TEXT_COMPRESSION_zTXt;
	    }
	    comment.text = (png_charp)s->data;
 	    comment.text_length = strlen(comment.text);
 	    png_set_text(png_ptr, info_ptr, &comment, 1);
	    /*@=observertrans =statictrans@*/
	    break;

	case GIFapplication:
	    png_write_chunk_start(png_ptr, 
				  (unsigned char *)"gIFx", 
				  (png_uint_32)s->size);
	    png_write_chunk_data(png_ptr, 
				 s->data, 
				 (png_size_t)s->size);
	    png_write_chunk_end(png_ptr);
	    break;

/* Plain Text Extensions are not supported because they represent a separate
   subimage, and PNG is explicitly a single-image format.  PNG's gIFt chunk
   has been officially deprecated.
*/
#if 0
	case GIFplaintext:
	    /* gIFt is 12 bytes longer than GCE, due to 32-bit ints and
	       rgb colors */
	    png_write_chunk_start(png_ptr, "gIFt", s->size+12);
	    memset(buffer, 0, 24);
	    buffer[2] = s->data[1];
	    buffer[3] = s->data[0];
	    buffer[6] = s->data[3];
	    buffer[7] = s->data[2];
	    buffer[10] = s->data[5];
	    buffer[11] = s->data[4];
	    buffer[14] = s->data[7];
	    buffer[15] = s->data[6];
	    buffer[16] = s->data[8];
	    buffer[17] = s->data[9];
	    buffer[18] = GifScreen.ColorMap[s->data[10]].red;
	    buffer[19] = GifScreen.ColorMap[s->data[10]].green;
	    buffer[20] = GifScreen.ColorMap[s->data[10]].blue;
	    buffer[21] = GifScreen.ColorMap[s->data[11]].red;
	    buffer[22] = GifScreen.ColorMap[s->data[11]].green;
	    buffer[23] = GifScreen.ColorMap[s->data[11]].blue;
	    png_write_chunk_s->data(png_ptr, buffer, 24);
	    png_write_chunk_s->data(png_ptr, s->data+12, s->size-12);
	    png_write_chunk_end(png_ptr);
	    break;
#endif

	case GIFgraphicctl:
	    buffer[0] = (s->data[0] >> 2) & 7;
	    buffer[1] = (s->data[0] >> 1) & 1;
	    buffer[2] = s->data[2];
	    buffer[3] = s->data[1];

	    png_write_chunk(png_ptr, (unsigned char *)"gIFg", buffer, 4);
	    break;

	default:
	    (void)fprintf(stderr, 
			  "gif2png internal error: encountered unused element type %c\n", 
			  s->GIFtype);
	    break;
	}
        /*@=branchstate@*/
	s = s->next;
    }
    png_write_end(png_ptr, info_ptr);

    /* clean up after the write, and free any memory allocated */
    png_destroy_write_struct(&png_ptr, &info_ptr);

    return errorcount;
}

int
MatteGIF(GifColor matte)
/* convert transparent pixels to a matte of given color */
{
    int icount = 0;

    /* apply matte color to image-local transparency values */
    for (current = &first; current ; current = current->next) {
	if (current->imagestruct) {
	    if (current->imagestruct->trans == -1)
		(void)fprintf(stderr, 
			"gif2png: no transparency color in image %d, matte argument ignored\n",
			icount);
	    else {
		if (verbose > 0) {
		    (void)fprintf(stderr, 
			"gif2png: transparent value in image %d is %d\n",  
			icount, current->imagestruct->trans);
		}

		current->imagestruct->colors[current->imagestruct->trans] = matte;
		current->imagestruct->trans = -1;
	    }
	}
    }
    return icount;
}

static int processfilter(void)
{
    int num_pics;
    struct GIFelement *start;

    current = &first;
    num_pics = ReadGIF (stdin);
    (void)fclose(stdin);

    if (num_pics != 1) {
	(void)fprintf(stderr, 
		      "gif2png: %d images in -f (filter) mode\n", num_pics);
	return 1;
    }

    /* eliminate use of transparency, if that is called for */
    if (matte)
	(void)MatteGIF(matte_color);

    start = NULL;
    for (current = first.next; current ; current = current->next) {
	if (start == NULL) start = current;
	if (current->GIFtype == GIFimage) {
	    (void)writefile(start, current, stdout, true);
	    start = NULL;
	    ++numpngs;
	}
    }
    free_mem();
    return 0;
}

static int processfile(char *fname, FILE *fp)
{
    char outname[1025]; /* MAXPATHLEN comes under too many names */
    int num_pics;
    struct GIFelement *start;
    int i; 
    bool suppress_delete = false;
    char *file_ext;
    struct utimbuf time_buf;

    if (fp == NULL) return 1;

    current = &first;

    num_pics = ReadGIF (fp);

    if (preserve_mtime)
    {
        struct stat stat_buf;

	/*@-compdef@*/
	/*@-unrecog@*//* needed because splint's POSIX library is buggy */
        if (fstat(fileno(fp), &stat_buf) < 0)
        {
            perror("Could not get input file times");
            return 1;
        }
	/*@=compdef@*/

	/*@-usedef@*/
        time_buf.actime  = stat_buf.st_atime;
        time_buf.modtime = stat_buf.st_mtime;
	/*@=usedef@*/
    }

    (void)fclose(fp);

    if (num_pics >= 0 && verbose > 1)
	(void)fprintf(stderr, "gif2png: number of images %d\n", num_pics);

    if (num_pics <= 0)
	return 1;

    if (webconvert)
	if (num_pics != 1)
	{
	    (void)fprintf(stderr, "gif2png: %s is multi-image\n", fname);
	    return 0;
	}
	else
	{
	    (void)printf("%s\n", fname);
	    return 0;
	}

    /* eliminate use of transparency, if that is called for */
    if (matte)
	(void)MatteGIF(matte_color);

    /* create output filename */

    (void)strcpy(outname, fname);

    file_ext = outname+strlen(outname);
    if (file_ext >= outname + 4)
	file_ext -= 4;

    if (strcmp(file_ext, ".gif") != 0 && strcmp(file_ext, ".GIF") != 0 &&
	strcmp(file_ext, "_gif") != 0 && strcmp(file_ext, "_GIF") != 0) {
	/* try to derive basename */
	file_ext = outname+strlen(outname);
	while(file_ext >= outname) {
	    if (*file_ext == '.' || *file_ext == '/' || *file_ext == '\\') break;
	    file_ext--;
	}
	if (file_ext<outname || *file_ext != '.') {
	    /* as a last resort, just add .png to the filename */
	    file_ext = outname+strlen(outname);
	}
    }

    (void)strcpy(file_ext, ".png"); /* images are named .png, .p01, .p02, ... */

    start = NULL;

    i = 0;

    for (current = first.next; current ; current = current->next) {
	if (start == NULL) start = current;
	if (current->GIFtype == GIFimage) {
	    i++;
	    if ((fp = fopen(outname, "wb")) == NULL) {
		perror(outname);
		return 1;
	    } else {
		suppress_delete |= writefile(start, current, fp, i == num_pics);
		(void)fclose(fp);

                if (preserve_mtime)
                {
		    /*@-compdef@*/
                    if (utime(outname, &time_buf) < 0)
                    {
                        perror("Could not set output file times");
                        return 1;
                    }
		    /*@=compdef@*/
                }

		++numpngs;
		start = NULL;
		/*@-bufferoverflowhigh*/
		(void)sprintf(file_ext, ".p%02d", i);
		/*@=bufferoverflowhigh*/
	    }
	}
    }

    free_mem();

    if (delete && !suppress_delete) {
	(void)unlink(fname);
    }

    return 0;
}

static bool input_is_terminal(void)
{
    return isatty(fileno(stdin))!=0;
}

static void bailout(int sig)
{
    (void)fprintf(stderr, "gif2png: GIF is fatally malformed, bailing out.\n");
    exit(2);
}

int main(int argc, char *argv[])
{
    FILE *fp;
    int i; 
    unsigned int background;
    int errors = 0;
    char name[1025];
    int ac;
    char *color;

    signal(SIGSEGV, bailout);

    software_chunk = true;

    for (ac = 1; ac < argc && argv[ac][0] == '-'; ac++)
    {
	for (i = 1; i < (int)strlen(argv[ac]); i++)
	    switch(argv[ac][i]) {
	    case 'b':
		if (ac >= argc - 1)
		{
		    (void)fputs("gif2png: missing background-matte argument\n",
				stderr);
		    exit(1);
		}
		color = argv[++ac];
		if (*color == '#')
		    color++;
	        (void)sscanf(color, "%2ux", &background);
		matte_color.red = (background >> 16) & 0xff;
		matte_color.green = (background >> 8) & 0xff; 
		matte_color.blue = background & 0xff;
		matte = true;
		goto skiparg;

	    case 'd':
		delete = true;
		break;

	    case 'f':
	    case '1': /* backward compatibility */
		filtermode = true;
		break;

	    case 'g':
		gamma_srgb = true;
		break;

	    case 'h':
		histogram = true;
		break;

	    case 'i':
		interlaced = PNG_INTERLACE_ADAM7;
		break;

	    case 'm':
		preserve_mtime = true;
		break;

	    case 'n':
		interlaced = PNG_INTERLACE_NONE;
		break;

	    case 'p':
		progress = true;
		break;

	    case 'r':
		recover = true;
		break;

	    case 's':
		software_chunk = false;
		break;

	    case 'v':
		++verbose;
		break;

	    case 'w':
		webconvert = true;
		break;

	    case 'O':
		optimize = true;
		break;

	    default:
		(void)fprintf(stderr, 
			      "gif2png: unknown option `-%c'\n", argv[ac][i]);
	    usage:
		(void)fprintf(stderr,
	"\n"
	"usage: gif2png [ -bdfghimnprstvwO ] [file[.gif]] ...\n"
	"\n"
	"   -b  replace background pixels with given RRGGBB color (hex digits)\n"
	"   -d  delete source GIF files after successful conversion\n"
	"   -f  allow use as filter, die on multi-image GIF\n"
	"   -g  write gamma=(1.0/2.2) and sRGB chunks\n"
	"   -h  generate PNG histogram chunks into color output files\n"
	"   -i  force conversion to interlaced PNG files\n"
	"   -m  preserve input file modification time\n"
	"   -n  force conversion to noninterlaced PNG files\n"
	"   -p  display progress of PNG writing in %%\n"
	"   -r  try to recover corrupted GIF files\n"
	"   -s  do not write Software text chunk\n"
	"   -v  verbose; display conversion statistics and debugging messages\n"
	"   -w  web probe, list images without animation\n"
	"   -O  optimize; remove unused color-table entries; use zlib level 9\n"
	"   -1  one-only; same as -f; provided for backward compatibility\n"
	"\n"
	"   If no source files are listed, stdin is converted to noname.png.\n"
	"\n"
	"   This is %s, %s\n", version, compile_info);
		return 1;
	    }
    skiparg:;
    }

    if (verbose > 1)
	(void)fprintf(stderr, "gif2png: %s, %s\n", version, compile_info);

    /* loop over arguments or use stdin */
    if (argc == ac) {
	if (input_is_terminal()) {
	    goto usage;
	}
	if (verbose > 1)
	    (void)fprintf(stderr, "stdin:\n");
	if (filtermode) {
	    if (processfilter() != 0) ++errors;
	} else {
	    (void)processfile("noname.gif", stdin);
	    ++numgifs;
	}
    } else {
	for (i = ac;i<argc; i++) {
	    /* make sure that there is enough space for a '.p<NUM>' suffix;
	       this check catches also the '.gif' case below. */
	    if (strlen(argv[i]) >= sizeof name - sizeof ".p" - 3 * sizeof(int)) {
		(void)fprintf(stderr, "%s: name too long\n", argv[i]);
		errors = 1;
		continue;
	    }

	    (void)strcpy(name, argv[i]);
	    if ((fp = fopen(name, "rb")) == NULL) {
		/* retry with .gif appended */
		(void)strcat(name, ".gif");
		fp = fopen(name,"rb");
	    }
	    if (fp == NULL) {
		perror(argv[i]);
		errors = 1;
	    } else {
		if (verbose > 1)
		    (void)fprintf(stderr, "%s:\n", name);
		errors |= processfile(name, fp);
		/* fp is closed in processfile */
		++numgifs;
	    }
	}
    }

    if (verbose > 0)
	(void)fprintf(stderr, "Done (%s).  Converted %ld GIF%s into %ld PNG%s.\n",
		      errors!=0? "with one or more errors" : "no errors detected", 
		      numgifs, (numgifs == 1) ? "" : "s", numpngs, (numpngs == 1)? "" : "s");

    return (errors > 0) ? 1 : 0;
}

static int check_recover(bool some_data)
{
    if(recover)
	return imagecount;
    if(!recover_message && (imagecount>0 || some_data)) {
	(void)fprintf(stderr, "gif2png: image reading error, use option -r to recover ");
	if(imagecount>0)
	    (void)fprintf(stderr, "%d complete image%s ", imagecount,
		    (imagecount>1?"s":""));
	if(imagecount>0 && some_data)
	    (void)fprintf(stderr, "and ");
	if(some_data)
	    (void)fprintf(stderr, "partial data of a broken image");
	(void)fprintf(stderr, "\n");
	recover_message=true;
    }
    return -1;
}

int
ReadGIF(FILE *fd)
{
    unsigned char buf[16];
    unsigned char c;
    GifColor      localColorMap[MAXCMSIZE];
    bool          useGlobalColormap;
    unsigned int  bitPixel;
    char          gif_version[4];
    int w, h, x_off, y_off;

    imagecount=0;
    recover_message=false;

    /*
     * Initialize GIF89 extensions
     */
    Gif89.transparent = -1;
    Gif89.delayTime = -1;
    Gif89.inputFlag = -1;
    Gif89.disposal = 0;

    if (! ReadOK(fd,buf,6)) {
	(void)fprintf(stderr, "gif2png: error reading magic number\n");
	return(-1);
    }

    if (strncmp((char *)buf,"GIF",3) != 0) {
	(void)fprintf(stderr, "gif2png: not a GIF file\n");
	return(-1);
    }

    strncpy(gif_version, (char *)buf + 3, 3);
    gif_version[3] = '\0';

    if ((strcmp(gif_version, "87a") != 0) && (strcmp(gif_version, "89a") != 0)) {
	(void)fprintf(stderr, "gif2png: bad version number, not '87a' or '89a', trying anyway\n");
    }

    if (! ReadOK(fd,buf,7)) {
	(void)fprintf(stderr, "gif2png: failed to read screen descriptor\n");
	return(-1);
    }

    GifScreen.Width           = LM_to_uint(buf[0],buf[1]);
    GifScreen.Height          = LM_to_uint(buf[2],buf[3]);
    GifScreen.BitPixel        = 2<<(buf[4]&0x07);
    GifScreen.ColorResolution = (((buf[4]&0x70)>>3)+1);
    GifScreen.ColorMap_present = BitSet(buf[4], GLOBALCOLORMAP);

    if (GifScreen.ColorMap_present) {     /* Global Colormap */

	if (ReadColorMap(fd, GifScreen.BitPixel, GifScreen.ColorMap)) {
	    (void)fprintf(stderr, "gif2png: error reading global colormap\n");
	    return(-1);
	}
    } else {
	/* the GIF spec says that if neither global nor local
	 * color maps are present, the decoder should use a system
	 * default map, which should have black and white as the
	 * first two colors. So we use black, white, red, green, blue,
	 * yellow, purple and cyan.
	 * I don't think missing color tables are a common case,
	 * at least it's not handled by most GIF readers.
	 */

	static int colors[]={0, 7, 1, 2, 4, 3, 5, 6};
	int i;

	/*@-predboolint -type@*/
	for(i=0 ; i<MAXCMSIZE-8 ; i++) {
	    GifScreen.ColorMap[i].red   = (colors[i&7]&1) ? ((255-i)&0xf8) : 0;
	    GifScreen.ColorMap[i].green = (colors[i&7]&2) ? ((255-i)&0xf8) : 0;
	    GifScreen.ColorMap[i].blue  = (colors[i&7]&4) ? ((255-i)&0xf8) : 0;
	}
	for(i=MAXCMSIZE-8 ; i<MAXCMSIZE; i++) {
	    GifScreen.ColorMap[i].red   = (colors[i&7]&1) ? 4 : 0;
	    GifScreen.ColorMap[i].green = (colors[i&7]&2) ? 4 : 0;
	    GifScreen.ColorMap[i].blue  = (colors[i&7]&4) ? 4 : 0;
	}
	/*@=predboolint =type@*/
    }

    if(GifScreen.ColorMap_present) {
	GifScreen.Background       = buf[5];
    } else {
	GifScreen.Background       = -1; /* background unspecified */
    }

    GifScreen.AspectRatio     = buf[6];

    for (;;) {
	if (! ReadOK(fd,&c,1)) {
	    (void)fprintf(stderr, "gif2png: EOF / read error on image data\n");
	    return check_recover(false);
	}

	if (c == GIFterminator) {           /* GIF terminator */
	    if (verbose > 1)
		(void)fprintf(stderr, "gif2png: end of GIF data stream\n");
	    return(imagecount);
	}

	if (c == GIFextension) {    /* Extension */
	    if (! ReadOK(fd,&c,1)) {
		(void)fprintf(stderr, "gif2png: EOF / read error on extension function code\n");
		return check_recover(false);
	    }
	    if(DoExtension(fd, c))
		return check_recover(false);
	    continue;
	}

	if (c != GIFimage) {                /* Not a valid start character */
	    (void)fprintf(stderr, "gif2png: bogus character 0x%02x\n",
			  (unsigned int)c);
	    return check_recover(false);
	}

	if (! ReadOK(fd,buf,9)) {
	    (void)fprintf(stderr,"gif2png: couldn't read left/top/width/height\n");
	    return check_recover(false);
	}

	useGlobalColormap = ! BitSet(buf[8], LOCALCOLORMAP);

	bitPixel = 1<<((buf[8]&0x07)+1);

	x_off = LM_to_uint(buf[0],buf[1]);
	y_off = LM_to_uint(buf[2],buf[3]);
	w = LM_to_uint(buf[4],buf[5]);
	h = LM_to_uint(buf[6],buf[7]);

	if (! useGlobalColormap) {
	    if (ReadColorMap(fd, bitPixel, localColorMap)) {
		(void)fprintf(stderr, 
			      "gif2png: error reading local colormap\n");
		return check_recover(false);
	    }

	    if(!ReadImage(fd, x_off, y_off, w, h, bitPixel,
			  localColorMap, BitSet(buf[8], INTERLACE))) {
		imagecount++;
	    }
	} else {
	    if(!GifScreen.ColorMap_present) {
		if (verbose > 1)
		    (void)fprintf(stderr, 
				  "gif2png: neither global nor local colormap, using default\n");
	    }

	    if(!ReadImage(fd, x_off, y_off, w, h, GifScreen.BitPixel,
			  GifScreen.ColorMap,  BitSet(buf[8], INTERLACE))) {
		imagecount++;
	    }
	}

	/*
	 * reset GIF89 extensions after image
	 */
	Gif89.transparent = -1;
	Gif89.delayTime = -1;
	Gif89.inputFlag = -1;
	Gif89.disposal = 0;
    }

    /* should never get here */
}

static bool
ReadColorMap(FILE *fd, unsigned int number, GifColor colors[])
{
    unsigned int   i;
    byte  rgb[3];

    for (i = 0; i < number; ++i) {
	if (!ReadOK(fd, rgb, sizeof(rgb))) {
	    (void)fprintf(stderr, "gif2png: bad colormap\n");
	    return(true);
	}

	colors[i].red   = rgb[0];
	colors[i].green = rgb[1];
	colors[i].blue  = rgb[2];
    }

    for (i = number; i<MAXCMSIZE; ++i) {
	colors[i].red   = 0;
	colors[i].green = 0;
	colors[i].blue  = 0;
    }

    return false;
}

static bool
DoExtension(FILE *fd, int label)
{
    static char   buf[256];
    char *str;
    char *p,*p2;
    ssize_t size;
    bool last_cr;

    switch (label) {
    case GIFplaintext:            /* Plain Text Extension */
	str = "Plain Text Extension";
	/*
	 * reset GIF89 extensions after Plain Text
	 */
	Gif89.transparent = -1;
	Gif89.delayTime = -1;
	Gif89.inputFlag = -1;
	Gif89.disposal = 0;
	if (verbose > 1)
	    (void)fprintf(stderr, "gif2png: got a 'Plain Text Extension' extension (skipping)\n");

	while (GetDataBlock(fd, (unsigned char*) buf) > 0)
	    continue;
	return (false);

    case GIFapplication:/* Application Extension */
	str = "Application Extension";
	break;

    case GIFcomment:      /* Comment Extension */
	allocate_element(); /* current now points to new element struct */

	/* the GIF89a spec defines comment extensions to contain ASCII
	   text, but doesn't specify what end-of-line delimiter is to
	   be used.  Most programs use DOS style (CR/LF), at least one
	   uses CR (Graphic Workshop for Windows), unix programs
	   probably use LF. We just delete CRs unless they are not
	   followed by a LF, then we convert CR to LF.  Even though 7
	   bit ASCII is specified, there are some GIF files with
	   comments that use codepage 437 and most DOS GIF readers
	   display this in the DOS charset (e.g. VPIC). We convert the
	   characters both in cp437 and latin1 and try to approximate
	   some of the box drawing chars.
	*/

	last_cr=false;

	while ((size=GetDataBlock(fd, (unsigned char*) buf)) > 0) {

	    p2=p=buf;

	    /* take care of CR as last char of one sub-block and no LF at first of
	       the next */
	    if(last_cr && *p!='\n') {
		store_block("\n",1);
		last_cr=false;
	    }

	    while(p-buf<size) {
		if(last_cr) {
		    if(*p!='\n')
			*p2++='\n';
		    last_cr=false;
		}
		if(*p=='\r')
		    last_cr=true;
		else
		    *p2++=c_437_l1[(unsigned char)*p];
		p++;
	    }
	    size=p2-buf;

	    store_block(buf, (size_t)size);
	}

	if (verbose > 1)
	    (void)fprintf(stderr, "gif2png: got a 'Comment Extension' extension\n");

	current->GIFtype=label;

	fix_current();
	return false;

    case GIFgraphicctl:           /* Graphic Control Extension */
	str = "Graphic Control Extension";
	size = GetDataBlock(fd, (unsigned char*) buf);
	/*@-shiftimplementation@*/
	Gif89.disposal    = (buf[0] >> 2) & 0x7;
	Gif89.inputFlag   = (buf[0] >> 1) & 0x1;
	Gif89.delayTime   = LM_to_uint(buf[1],buf[2]);
	/*@=shiftimplementation@*/
	if ((buf[0] & 0x1) != 0)
	    Gif89.transparent = (int)((unsigned char)buf[3]);

	if(Gif89.disposal==0 && Gif89.inputFlag==0 &&
	   Gif89.delayTime==0) {

	    /* do not keep GCEs only indicating transparency */

	    while (GetDataBlock(fd, (unsigned char*) buf) > 0)
		;

	    return (false);
	} else {
	    /* copy block already read */
	    allocate_element(); /* current now points to new element struct */

	    goto copy_block;
	}
    default:
	if (verbose > 1)
	    (void)fprintf(stderr, "gif2png: skipping unknown extension 0x%02x\n",
		    (unsigned char)label);
	while (GetDataBlock(fd, (unsigned char*) buf) > 0)
	    ;
	return (true);
    }

    allocate_element(); /* current now points to new element struct */

    while ((size=GetDataBlock(fd, (unsigned char*) buf)) > 0) {
    copy_block:
	store_block(buf, (size_t)size);
    }

    if (verbose > 1)
	(void)fprintf(stderr, "gif2png: got a '%s' extension\n", str);

    current->GIFtype=label;

    fix_current();

    return (false);
}

static ssize_t
GetDataBlock(FILE *fd, unsigned char *buf)
{
    size_t count;

    count = 0;
    if (! ReadOK(fd, &count, 1)) {
	(void)fprintf(stderr, "gif2png: error in getting DataBlock size\n");
	return -1;
    }

    ZeroDataBlock = count == 0;

    if ((count != 0) && (! ReadOK(fd, buf, count))) {
	(void)fprintf(stderr, "gif2png: error in reading DataBlock\n");
	return -1;
    }

    return((ssize_t)count);
}

static void initLWZ(unsigned int input_code_size)
{
    /*@-shiftnegative@*/
    set_code_size = (int)input_code_size;
    code_size     = set_code_size + 1;
    clear_code    = 1 << set_code_size ;
    end_code      = clear_code + 1;
    max_code_size = 2 * clear_code;
    max_code      = clear_code + 2;
    /*@=shiftnegative@*/

    curbit = lastbit = 0;
    last_byte = 2;
    get_done = false;

    return_clear = true;

    sp = stack;
}

static int nextCode(FILE *fd, int code_size)
{
    static unsigned char    buf[280];
    static int maskTbl[16] = {
	0x0000, 0x0001, 0x0003, 0x0007,
	0x000f, 0x001f, 0x003f, 0x007f,
	0x00ff, 0x01ff, 0x03ff, 0x07ff,
	0x0fff, 0x1fff, 0x3fff, 0x7fff,
    };
    int i, j, end;
    long ret;

    if (return_clear) {
	return_clear = false;
	return clear_code;
    }

    end = curbit + code_size;

    if (end >= lastbit) {
	ssize_t     count;

	if (get_done) {
	    if (verbose!=0 && curbit >= lastbit) {
		(void)fprintf(stderr, "gif2png: ran off the end of input bits\n");
	    }
	    return -1;
	}
	buf[0] = buf[last_byte-2];
	buf[1] = buf[last_byte-1];

	if ((count = GetDataBlock(fd, &buf[2])) == 0)
	    get_done = true;

	if (count<0) return -1;

	last_byte = 2 + (int)count;
	curbit = (curbit - lastbit) + 16;
	lastbit = (2+(int)count)*8 ;

	end = curbit + code_size;
    }

    j = end / 8;
    i = curbit / 8;

    /*@-shiftimplementation@*/
    if (i == j)
	ret = (long)buf[i];
    else if (i + 1 == j)
	ret = (long)buf[i] | ((long)buf[i+1] << 8);
    else
	ret = (long)buf[i] | ((long)buf[i+1] << 8) | ((long)buf[i+2] << 16);

    /*@-shiftnegative@*/
    if( code_size < 16) {
        ret = (ret >> (curbit % 8)) & maskTbl[code_size];
    } else {
        (void)fprintf(stderr, "gif2png: LWZMinimumCodeSize can't be bigger than 15\n");
        exit(1);
    }
    /*@=shiftnegative@*/
    /*@=shiftimplementation@*/

    curbit += code_size;

    return (int)ret;
}

static int nextLWZ(FILE *fd)
{
    static int       table[2][(1<< MAX_LWZ_BITS)];
    static int       firstcode, oldcode;
    int              code;
    register int     i;

    while ((code = nextCode(fd, code_size)) >= 0) {
	int              incode;
	if (code == clear_code) {
	    /* corrupt GIFs can make this happen */
	    if (clear_code >= (1<<MAX_LWZ_BITS)) {
		return -2;
	    }

	    for (i = 0; i < clear_code; ++i) {
		table[0][i] = 0;
		table[1][i] = i;
	    }
	    for (; i < (1<<MAX_LWZ_BITS); ++i)
		table[0][i] = table[1][i] = 0;
	    code_size = set_code_size+1;
	    max_code_size = 2*clear_code;
	    max_code = clear_code+2;
	    sp = stack;
	    do {
		firstcode = oldcode = nextCode(fd, code_size);
	    } while (firstcode == clear_code);

	    return firstcode;
	}
	if (code == end_code) {
	    ssize_t         count;
	    unsigned char   buf[260];

	    if (ZeroDataBlock)
		return -2;

	    while ((count = GetDataBlock(fd, buf)) > 0)
		;

	    if (count != 0) {
		(void)fprintf(stderr, "gif2png: missing EOD in data stream (common occurrence)\n");
	    }
	    return -2;
	}

	incode = code;

	if (code >= max_code) {
	    *sp++ = firstcode;
	    code = oldcode;
	}

	while (code >= clear_code) {
	    *sp++ = table[1][code];
	    if (code == table[0][code]) {
		(void)fprintf(stderr, "gif2png: circular table entry BIG ERROR\n");
		exit(1);
	    }
	    if ((size_t)((char *)sp - (char *)stack) >= sizeof(stack)) {
		(void)fprintf(stderr, "gif2png: circular table STACK OVERFLOW!\n");
		exit(1);
	    }
	    code = table[0][code];
	}

	*sp++ = firstcode = table[1][code];

	if ((code = max_code) <(1<<MAX_LWZ_BITS)) {
	    table[0][code] = oldcode;
	    table[1][code] = firstcode;
	    ++max_code;
	    if ((max_code >= max_code_size) &&
		(max_code_size < (1<<MAX_LWZ_BITS))) {
		max_code_size *= 2;
		++code_size;
	    }
	}

	oldcode = incode;

	if (sp > stack)
	    return *--sp;
    }
    return code;
}

static byte *
get_prev_line(int width, int height, int line)
{
    int prev_line;
    byte *res;

    prev_line=inv_interlace_line(height,line)-1;
    while(interlace_line(height, prev_line)>=line)
	prev_line--;

    res = current->data + width*interlace_line(height, prev_line);

    return res;
}

static bool
ReadImage(FILE *fd, int x_off, int y_off, int width, int height, 
	  unsigned int cmapSize, GifColor cmap[], bool interlace)
{
    unsigned char *dp, c;
    int           v;
    int           xpos = 0, ypos = 0;
    unsigned char *image;
    int i;
    unsigned long *count;

    /*
    **  Initialize the compression routines
    */
    if (! ReadOK(fd,&c,1)) {
	(void)fprintf(stderr, "gif2png: EOF / read error on image data\n");
	return(true);
    }

    initLWZ(c);

    if (verbose > 1)
	(void)fprintf(stderr, "gif2png: reading %d by %d%s GIF image\n",
		width, height, interlace ? " interlaced" : "" );

    allocate_image();
    /* since we know how large the image will be, we set the size in advance.
       This saves a lot of realloc calls, which may require copying memory. */

    set_size((size_t)width*height);

    image=xalloc((size_t)width);

    current->imagestruct->offset_x = x_off;
    current->imagestruct->offset_y = y_off;
    current->imagestruct->width    = (png_uint_32)width;
    current->imagestruct->height   = (png_uint_32)height;
    current->imagestruct->trans    = Gif89.transparent;
    current->imagestruct->interlace= interlace;

    /*@-mayaliasunique@*/
    memcpy(current->imagestruct->colors, cmap, sizeof(GifColor)*MAXCMSIZE);
    /*@=mayaliasunique@*/

    count=current->imagestruct->color_count;

    for(i=0;i<MAXCMSIZE;i++) {
	count[i]=0;
    }

    for (ypos = 0; ypos < height; ypos++) {
	dp=image;
	for (xpos = 0; xpos < width; xpos++) {
	    if ((v = readLWZ(fd)) < 0 || v >= (int)cmapSize) {
		if(v >= (int)cmapSize)
		    (void)fprintf(stderr, 
				  "gif2png: reference to undefined colormap entry\n");

		if(xpos>0 || ypos>0) {
		    if(recover) {
			if(!interlace) {
			    /* easy part, just fill the rest of the `screen' with color 0 */
			    memset(image+xpos,0, (size_t)(width-xpos));
			    store_block((char *)image,(size_t)width);
			    ypos++;

			    memset(image, 0, (size_t)width);
			    for( ; ypos < height ; ypos++)
				store_block((char *)image,(size_t)width);
			} else {
			    /* interlacing recovery is a bit tricky */

			    if(xpos>0) {
				if((inv_interlace_line(height, ypos)&7)==0) {
				    /* in 1st pass */
				    memset(image+xpos, 0, (size_t)(width-xpos));
				} else {
				    /* pass >=2 */
				    memcpy(image+xpos, get_prev_line(width, height, ypos)+xpos,
					   (size_t)(width-xpos));
				}
				store_block((char *)image,(size_t)width);
				ypos++;
			    }

			    /* fill rest of 1st pass with color 0 */
			    memset(image, 0, (size_t)width);
			    for( ; (inv_interlace_line(height, ypos)&7)==0 ; ypos++)
				store_block((char *)image,(size_t)width);

			    /* all other passes, copy from line above */
			    for( ; ypos<height ; ypos++) {
				memcpy(image, get_prev_line(width, height, ypos), (size_t)width);
				store_block((char *)image,(size_t)width);
			    }
			}
			goto fini;
		    } else {
			(void)check_recover(true);
			return(true);
		    }
		} else {
		    return(true);
		}
	    }

	    count[v]++;

	    *dp++ = (unsigned char)v;
	}
	store_block((char *)image,(size_t)width);
    }
fini:

    while(readLWZ(fd)>=0)
	continue;

    /*@-usedef@*/
    (void)free(image);
    /*@=usedef@*/

    fix_current();

    /*
     * reset GIF89 extensions after image
     */

    Gif89.transparent = -1;
    Gif89.delayTime = -1;
    Gif89.inputFlag = -1;
    Gif89.disposal = 0;

    return(false);
}

